arguments.argument:
if global.gamePaused=false
{
  makeEnemyActive(0)
  if bActive=true and stunnedTime=0
  {
    //move
    moveTime+=1
    if moveTime>=moveWait and jumpTime<jumpWait and yVel=0
    {
      image_index=1
      y-=4
      yVel=-0.2
      if x>oCharacter.x
        xVel=-2
      else
        xVel=2
      moveWait=15+irandom(30)
      moveTime=0
    }
    //jump
    jumpTime+=1
    if jumpTime=jumpWait and yVel=0
    {
      image_index=1
      y-=4
      yVel=-3
      if x>oCharacter.x
        xVel=-2
      else
        xVel=2
    }
    
    yVel+=0.2
    if isCollisionBottom(1)
    {
      image_index=0
      xVel=0
      yVel=0
      if jumpTime>=jumpWait
      {
        jumpWait=60+irandom(100)
        jumpTime=0
      }
    }
    if isCollisionLeft(1)
      xVel=runAcc
    if isCollisionRight(1)
      xVel=-runAcc
    moveTo(xVel,yVel)
    if isCollisionSolid()
      y-=1
    if y>room_height+30
      instance_destroy()
  }
  enemyStepEvent()
}
